const ethers = require('ethers');

class SecureDApp {
  constructor() {
    this.provider = null;
    this.signer = null;
    this.contract = null;
  }

  async initialize(contractAddress, contractABI) {
    if (typeof window.ethereum === 'undefined') {
      throw new Error('MetaMask or compatible wallet not found');
    }

    this.provider = new ethers.providers.Web3Provider(window.ethereum);
    
    await window.ethereum.request({ method: 'eth_requestAccounts' });
    
    this.signer = this.provider.getSigner();
    this.contract = new ethers.Contract(contractAddress, contractABI, this.signer);
    
    const network = await this.provider.getNetwork();
    console.log('Connected to network:', network.name);
    
    return {
      address: await this.signer.getAddress(),
      network: network.name,
      chainId: network.chainId
    };
  }

  async getTransactionPreview(functionName, params, options = {}) {
    if (!this.contract) {
      throw new Error('Contract not initialized');
    }

    const gasEstimate = await this.contract.estimateGas[functionName](...params, options);
    const gasPrice = await this.provider.getGasPrice();
    const feeData = await this.provider.getFeeData();
    
    return {
      estimatedGas: gasEstimate.toString(),
      gasPrice: ethers.utils.formatUnits(gasPrice, 'gwei'),
      maxFeePerGas: feeData.maxFeePerGas ? ethers.utils.formatUnits(feeData.maxFeePerGas, 'gwei') : null,
      maxPriorityFeePerGas: feeData.maxPriorityFeePerGas ? ethers.utils.formatUnits(feeData.maxPriorityFeePerGas, 'gwei') : null,
      estimatedCost: ethers.utils.formatEther(gasEstimate.mul(gasPrice))
    };
  }

  validateTransactionParams(params) {
    const validated = {};
    
    if (params.value) {
      if (typeof params.value === 'string' && !isNaN(params.value)) {
        validated.value = ethers.utils.parseEther(params.value);
      } else {
        throw new Error('Invalid value parameter');
      }
    }
    
    if (params.gasLimit) {
      if (typeof params.gasLimit === 'string' || typeof params.gasLimit === 'number') {
        validated.gasLimit = ethers.BigNumber.from(params.gasLimit);
      } else {
        throw new Error('Invalid gasLimit parameter');
      }
    }
    
    if (params.maxFeePerGas) {
      validated.maxFeePerGas = ethers.utils.parseUnits(params.maxFeePerGas.toString(), 'gwei');
    }
    
    if (params.maxPriorityFeePerGas) {
      validated.maxPriorityFeePerGas = ethers.utils.parseUnits(params.maxPriorityFeePerGas.toString(), 'gwei');
    }
    
    return validated;
  }

  async executeContractFunction(functionName, functionParams = [], transactionOptions = {}) {
    if (!this.contract) {
      throw new Error('Contract not initialized');
    }

    if (!this.contract[functionName]) {
      throw new Error(`Function ${functionName} not found in contract`);
    }

    const validatedOptions = this.validateTransactionParams(transactionOptions);
    
    const userAddress = await this.signer.getAddress();
    console.log('Transaction will be sent from:', userAddress);
    
    const preview = await this.getTransactionPreview(functionName, functionParams, validatedOptions);
    console.log('Transaction preview:', preview);
    
    const tx = await this.contract[functionName](...functionParams, validatedOptions);
    
    console.log('Transaction submitted:', tx.hash);
    console.log('Waiting for confirmation...');
    
    const receipt = await tx.wait();
    
    return {
      transactionHash: receipt.transactionHash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status,
      events: receipt.events
    };
  }

  async callContractView(functionName, functionParams = []) {
    if (!this.contract) {
      throw new Error('Contract not initialized');
    }

    if (!this.contract[functionName]) {
      throw new Error(`Function ${functionName} not found in contract`);
    }

    const result = await this.contract[functionName](...functionParams);
    return result;
  }

  async sendTransaction(to, value, data = '0x') {
    if (!this.signer) {
      throw new Error('Signer not initialized');
    }

    if (!ethers.utils.isAddress(to)) {
      throw new Error('Invalid recipient address');
    }

    const txRequest = {
      to: to,
      value: ethers.utils.parseEther(value.toString()),
      data: data
    };

    const gasEstimate = await this.signer.estimateGas(txRequest);
    txRequest.gasLimit = gasEstimate;

    const feeData = await this.provider.getFeeData();
    if (feeData.maxFeePerGas && feeData.maxPriorityFeePerGas) {
      txRequest.maxFeePerGas = feeData.maxFeePerGas;
      txRequest.maxPriorityFeePerGas = feeData.maxPriorityFeePerGas;
    } else {
      txRequest.gasPrice = await this.provider.getGasPrice();
    }

    const tx = await this.signer.sendTransaction(txRequest);
    
    console.log('Transaction sent:', tx.hash);
    
    const receipt = await tx.wait();
    
    return {
      transactionHash: receipt.transactionHash,
      blockNumber: receipt.blockNumber,
      gasUsed: receipt.gasUsed.toString(),
      status: receipt.status
    };
  }

  async signMessage(message) {
    if (!this.signer) {
      throw new Error('Signer not initialized');
    }

    const signature = await this.signer.signMessage(message);
    return signature;
  }

  async verifySignature(message, signature, expectedAddress) {
    const recoveredAddress = ethers.utils.verifyMessage(message, signature);
    return recoveredAddress.toLowerCase() === expectedAddress.toLowerCase();
  }

  async getBalance(address) {
    if (!this.provider) {
      throw new Error('Provider not initialized');
    }

    const balance = await this.provider.getBalance(address);
    return ethers.utils.formatEther(balance);
  }

  async waitForTransaction(txHash, confirmations = 1) {
    if (!this.provider) {
      throw new Error('Provider not initialized');
    }

    const receipt = await this.provider.waitForTransaction(txHash, confirmations);
    return receipt;
  }

  async switchNetwork(chainId) {
    try {
      await window.ethereum.request({
        method: 'wallet_switchEthereumChain',
        params: [{ chainId: ethers.utils.hexValue(chainId) }],
      });
      this.provider = new ethers.providers.Web3Provider(window.ethereum);
      this.signer = this.provider.getSigner();
    } catch (error) {
      if (error.code === 4902) {
        throw new Error('Network not added to wallet');
      }
      throw error;
    }
  }

  disconnect() {
    this.provider = null;
    this.signer = null;
    this.contract = null;
  }
}

const dapp = new SecureDApp();

async function initializeDApp(contractAddress, contractABI) {
  try {
    const connectionInfo = await dapp.initialize(contractAddress, contractABI);
    console.log('DApp initialized:', connectionInfo);
    return connectionInfo;
  } catch (error) {
    console.error('Initialization error:', error.message);
    throw error;
  }
}

